UPDATE shelf_capacity
SET current_pin_boxes = current_pin_boxes + #{quantity},
    update_time = NOW()
WHERE id = #{id}
  AND max_pin_boxes >= current_pin_boxes + #{quantity}

UPDATE shelf_capacity
SET current_shim_packs = current_shim_packs + #{quantity},
    update_time = NOW()
WHERE id = #{id}
  AND max_shim_packs >= current_shim_packs + #{quantity}
